impl From<u16> for Perl {
    #[inline]
    fn from(x: u16) -> Self {
        num::FromPrimitive::from_u16(x).unwrap_or(Self::Error)
    }
}

// Perl == u16
impl PartialEq<u16> for Perl {
    #[inline]
    fn eq(&self, x: &u16) -> bool {
        *self == Into::<Self>::into(*x)
    }
}

// u16 == Perl
impl PartialEq<Perl> for u16 {
    #[inline]
    fn eq(&self, x: &Perl) -> bool {
        *x == *self
    }
}
